#include <stdio.h>
#include <stdint.h>
#define MOD 1000000007LL

int64_t mod_pow(int64_t base, int64_t exp) {
    int64_t res = 1 % MOD;
    base %= MOD;
    while (exp > 0) {
        if (exp & 1) res = (res * base) % MOD;
        base = (base * base) % MOD;
        exp >>= 1;
    }
    return res;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long n, k;
        scanf("%lld %lld", &n, &k);
        if (n == 1) {
            printf("%lld\n", (k == 1) ? 1 : 0);
            continue;
        }
        long long kn = k * n % MOD;
        long long term1 = mod_pow(kn, n - 2);
        long long base2 = (k % MOD) * ((n - 1) % MOD) % MOD;
        long long exp2 = n * (k - 1);
        long long term2 = mod_pow(base2, exp2);
        long long ans = term1 * term2 % MOD;
        printf("%lld\n", ans);
    }
    return 0;
}

